using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);

        try
        {
            // Use a simple web search approach via DuckDuckGo instant answer API
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetAsync(url);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync();
            var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<SearchResult>();

            // Extract abstract if available
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();

            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add(new SearchResult(
                    Title: $"{abstractSource} Summary",
                    Snippet: abstractText,
                    Url: abstractUrl ?? ""));
            }

            // Extract related topics
            if (root.TryGetProperty("RelatedTopics", out var relatedTopics))
            {
                foreach (var topic in relatedTopics.EnumerateArray())
                {
                    if (results.Count >= maxResults) break;

                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;

                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add(new SearchResult(
                            Title: text.Length > 60 ? text[..60] + "..." : text,
                            Snippet: text,
                            Url: firstUrl ?? ""));
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing the search query.";
            }

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed: {ex.Message}. Try again with a different query.";
        }
    }

    private record SearchResult(string Title, string Snippet, string Url);
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Saves a research note with a topic tag and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short topic tag for categorizing this note (e.g., 'definition', 'history', 'key-finding')")] string topic,
        [Description("The content of the note to save")] string content)
    {
        var note = new ResearchNote(
            Id: _notes.Count + 1,
            Topic: topic,
            Content: content,
            Timestamp: DateTime.UtcNow);

        _notes.Add(note);
        return $"Note #{note.Id} saved under topic '{topic}'.";
    }

    [Description("Retrieves all saved research notes, optionally filtered by topic.")]
    public string GetNotes(
        [Description("Optional topic filter. Leave empty to get all notes.")] string? topic = null)
    {
        var filtered = string.IsNullOrWhiteSpace(topic)
            ? _notes
            : _notes.Where(n => n.Topic.Contains(topic, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
        {
            return string.IsNullOrWhiteSpace(topic)
                ? "No notes saved yet."
                : $"No notes found for topic '{topic}'.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"--- Research Notes ({filtered.Count} total) ---");
        foreach (var note in filtered)
        {
            sb.AppendLine($"[#{note.Id}] [{note.Topic}] {note.Content}");
        }
        return sb.ToString();
    }

    [Description("Gets a count of how many notes have been saved so far.")]
    public string GetNoteCount()
    {
        var topicGroups = _notes.GroupBy(n => n.Topic).Select(g => $"{g.Key}: {g.Count()}");
        return $"Total notes: {_notes.Count}. By topic: {string.Join(", ", topicGroups)}";
    }

    private record ResearchNote(int Id, string Topic, string Content, DateTime Timestamp);
}

