using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Configure logging
builder.Logging.SetMinimumLevel(LogLevel.Warning);

// Register HttpClient for web search
builder.Services.AddHttpClient<WebSearchTool>(client =>
{
    client.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    client.Timeout = TimeSpan.FromSeconds(15);
});

// Register AI chat client via MEAI abstraction
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(services =>
    new OpenAIClient(apiKey)
        .GetChatClient(modelId)
        .AsIChatClient());

var host = builder.Build();

// Resolve services
var chatClient = host.Services.GetRequiredService<IChatClient>();
var httpClientFactory = host.Services.GetRequiredService<IHttpClientFactory>();
var httpClient = httpClientFactory.CreateClient(nameof(WebSearchTool));

// Create tool instances
var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

// Register tools with the agent
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(noteTaking.SaveNote),
    AIFunctionFactory.Create(noteTaking.GetNotes),
    AIFunctionFactory.Create(noteTaking.GetNoteCount),
};

// Get the research topic from the user
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}");
Console.WriteLine("─────────────────────────────────────────\n");

// Configure the agent with guardrails
var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = tools,
    ToolMode = ChatToolMode.Auto,
};

var systemPrompt = $"""
    You are a research agent. Your goal is to thoroughly research the given topic using the available tools.

    Follow this process:
    1. Search the web for information about the topic using multiple varied queries.
    2. Save important findings as notes using the note-taking tool, categorizing them by subtopic.
    3. After gathering enough information (at least 3-5 notes), retrieve all your notes.
    4. Provide a comprehensive summary of your research findings to the user.

    Be thorough but focused. Use specific search queries to find diverse information.
    Always save key findings before summarizing.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
};

// Run the agent loop with iteration limit
const int maxIterations = 15;
var iteration = 0;

while (iteration < maxIterations)
{
    iteration++;
    var response = await chatClient.GetResponseAsync(messages, chatOptions);

    // Process all response messages
    foreach (var message in response.Messages)
    {
        messages.Add(message);
    }

    // Check if the model made tool calls (indicated by function call content)
    var hasFunctionCalls = response.Messages
        .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

    var hasFunctionResults = response.Messages
        .Any(m => m.Contents.OfType<FunctionResultContent>().Any());

    // If no tool calls were made, the agent is done
    if (!hasFunctionCalls && !hasFunctionResults)
    {
        // Print the final response
        var finalText = response.Messages
            .Where(m => m.Role == ChatRole.Assistant)
            .SelectMany(m => m.Contents.OfType<TextContent>())
            .LastOrDefault()?.Text;

        if (!string.IsNullOrWhiteSpace(finalText))
        {
            Console.WriteLine("═══ Research Summary ═══\n");
            Console.WriteLine(finalText);
            Console.WriteLine("\n═══════════════════════\n");
        }
        break;
    }

    // Log progress
    var toolCalls = response.Messages
        .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
        .Select(fc => fc.Name);

    Console.WriteLine($"  [Step {iteration}] Tools used: {string.Join(", ", toolCalls)}");
}

if (iteration >= maxIterations)
{
    Console.WriteLine("\n⚠ Agent reached maximum iterations. Partial results may be available.");
}

Console.WriteLine($"\nResearch complete. ({iteration} steps taken)");

